sql:
SELECT COUNT(impact_id) 
FROM intervention_impact 
WHERE impact_severity = 'High';

SELECT COUNT(report_id)
FROM weekly_flags
WHERE flag_value = 'None';

SELECT COUNT(*)
FROM weekly_disease_counts
WHERE count > 1;

